This solves the problem of loading it with flex, but causes errors in the "official" swagger editor and other swagger-parser related things. I am not sure, if this is a reliable and "portable" solution of the problem. I also created a second version with a problem of referencen to `#/parameters` which also fails

```json
{
	"swagger": "2.0",
	"info": {
		"title": 	"Sample Rest API",
		"version":	"1.0"
	},
	"basePath": "/",
	"schemes": 	["http"],
	"consumes": ["application/json"],
	"produces": ["application/json"],
	"paths" : {
		"/status" : {
			"post" : {
				"parameters" : [{
						"name" : "token",
						"in" : "body",
						"schema": {
							"$ref": "#/parameters/tokenParameter"
						}
					}
				],
				"responses" : {
					"200" : {
						"description" : "retrieves the status"
					}
				}
			}
		}
	},
	"parameters": {
		"tokenParameter": {
			"in": "body",
			"name": "token",
			"schema": { "$ref": "#/definitions/TokenObj" }
		}	
	},
	"definitions": {
		"TokenObj" : {
			"type": "object",
			"required": ["magic", "timestamp"],
			"properties": {
					"magic" : {
						"type": "string"
					},
					"timestamp": {
						"type": "string"
					}
			}
		}
	}
}
```
The suggested solution by you isn't applicable in this case.
As a further problem, flex insists that as a parameter a simple reference is not enough. There have to be at least a `name` and `in`. However, the swagger spec schema specifies this case of only a schema reference like this: 
```json
		"parameters" : [{
										"$ref": "#/parameters/tokenParameter"
			}
		]
```

My examplse are valid in the editor. I know that the editor does have its flaws, because sometimes it isn't parsing this strictly enough. However, in my opinion it seems to be a problem with flex, because I also want to use my API specification in other tools.

This patch did not solve my issue. The issue appears to me to be that the `update` function in `widget-editable.js` is asking for this:

```javascript
update: function( c, wo ) {
      ....
     cols = tse.getColumns( c, wo ).join( ',' );
````

The first time this runs (when I initialize the table), cols is something like this

```
td:nth-child(1),td:nth-child(2),td:nth-child(3)
```

but when it runs after that, cols is empty. This is because `getColumns` only works once. It only works once because the logic in it sets `wo.editable_columnsArray` the first time and this prevents it from doing anything ever again. 

The following patch to widget-editable.js fixes my issue, please pardon the lack of proper whitespace preservation:

```patch
--- a/js/widgets/widget-editable.js
+++ b/public/js/widget-editable.js
@@ -10,7 +10,8 @@
 	var tse = $.tablesorter.editable = {
 		namespace : '.tseditable',
 		// last edited class name
-		lastEdited: 'tseditable-last-edited-cell',
+	        lastEdited: 'tseditable-last-edited-cell',
+                myCols: [],
 
 		editComplete: function( c, wo, $cell, refocus ) {
 			c.$table
@@ -48,7 +49,7 @@
 			var indx, tmp,
 				colIndex = [],
 				cols = [];
-			if ( !wo.editable_columnsArray && $.type( wo.editable_columns ) === 'string' && wo.editable_columns.indexOf( '-' ) >= 0 ) {
+                        if ( !wo.editable_columnsArray && $.type( wo.editable_columns ) === 'string' && wo.editable_columns.indexOf( '-' ) >= 0 ) {
 				// editable_columns can contain a range string ( i.e. '2-4' )
 				tmp = wo.editable_columns.split( /\s*-\s*/ );
 				indx = parseInt( tmp[ 0 ], 10 ) || 0;
@@ -60,6 +61,7 @@
 					colIndex.push( indx );
 					cols.push( 'td:nth-child(' + ( indx + 1 ) + ')' );
 				}
+                                tse.myCols = cols;
 			} else if ( $.isArray( wo.editable_columns ) ) {
 				$.each( wo.editable_columnsArray || wo.editable_columns, function( i, col ) {
 					if ( col < c.columns ) {
@@ -67,12 +69,14 @@
 						cols.push( 'td:nth-child(' + ( col + 1 ) + ')' );
 					}
 				});
+                                tse.myCols = cols;
 			}
 			if ( !wo.editable_columnsArray ) {
 				wo.editable_columnsArray = colIndex;
 				wo.editable_columnsArray.sort(function(a, b){ return a - b; });
 			}
-			return cols;
+
+  		        return tse.myCols;
 		},
 
 		update: function( c, wo ) {

```

