class TestIdempotentTransaction(TestCase):

    def test_is_idempotent(self):
        @idempotent_transaction
        def create_user():
            models.User.objects.create(
                username='foo',
            )
        create_user()
        self.assertFalse(models.User.objects.exists())
```

I was able to get around this by adding a step to my pipeline that picked up the `strategy.request.user` to not create new accounts like so:

```
def apiUserPipeline(strategy, details, backend, user=None, *args, **kwargs):
    if  user is None and strategy.request.user:
        return {'user': strategy.request.user}
```

